# name: length_penalty_scaling
# description: Mean choice rate of the shorter sequence when both sequences are highly imbalanced (>0.4), testing if the penalty accumulates linearly.
import numpy as np


def test_statistic(df):
    mask = (
        (df["imbalance_a"] > 0.4) & (df["imbalance_b"] > 0.4) & (df["n_a"] != df["n_b"])
    )
    shorter_chosen = np.where(
        df.loc[mask, "n_a"] < df.loc[mask, "n_b"],
        df.loc[mask, "chose_left"],
        1 - df.loc[mask, "chose_left"],
    )
    return float(shorter_chosen.mean())

# name: extreme_proportion_penalty
# description: Mean choice rate of sequence A when it has extreme proportion imbalance (>0.6) and sequence B is balanced (<0.2).
import numpy as np


def test_statistic(df):
    mask = (df["imbalance_a"] > 0.6) & (df["imbalance_b"] < 0.2)
    return float(df.loc[mask, "chose_left"].mean())

# name: heads_vs_tails_asymmetry
# description: Mean choice rate of sequence A when A is head-heavy and B is tail-heavy, but equally imbalanced, testing for asymmetry.
import numpy as np


def test_statistic(df):
    mask = (
        (df["p_a"] > 0.6)
        & (df["p_b"] < 0.4)
        & (np.abs((df["p_a"] - 0.5) + (df["p_b"] - 0.5)) < 0.1)
    )
    return float(df.loc[mask, "chose_left"].mean())

# name: short_vs_long_preference
# description: Mean choice rate of sequence A when A is very short (n <= 4) and B is long (n >= 7), capturing baseline typicality length effects.
import numpy as np


def test_statistic(df):
    mask = (df["n_a"] <= 4) & (df["n_b"] >= 7)
    return float(df.loc[mask, "chose_left"].mean())

# name: extreme_alternation_penalty
# description: Mean choice rate of sequence A when it has an extreme alternation rate (0 or 1) and sequence B is moderate (0.2 to 0.8).
import numpy as np


def test_statistic(df):
    mask = (
        ((df["p_alts_a"] == 0) | (df["p_alts_a"] == 1))
        & (df["p_alts_b"] > 0.2)
        & (df["p_alts_b"] < 0.8)
    )
    return float(df.loc[mask, "chose_left"].mean())

# name: periodicity_aversion
# description: Mean choice rate of sequence A when it is more periodic than B, controlling for similar proportion and alternation rates.
import numpy as np


def test_statistic(df):
    mask = (
        (np.abs(df["p_a"] - df["p_b"]) < 0.2)
        & (np.abs(df["p_alts_a"] - df["p_alts_b"]) < 0.2)
        & (df["periodicity_a"] > df["periodicity_b"] + 0.2)
    )
    return float(df.loc[mask, "chose_left"].mean())

# name: under_vs_over_alternation
# description: Mean choice rate of sequence A when A is under-alternating (<0.4) and B is over-alternating (>0.6) with similar imbalance.
import numpy as np


def test_statistic(df):
    mask = (
        (df["p_alts_a"] < 0.4)
        & (df["p_alts_b"] > 0.6)
        & (np.abs(df["imbalance_a"] - df["imbalance_b"]) < 0.2)
    )
    return float(df.loc[mask, "chose_left"].mean())

# name: max_run_length_aversion
# description: Mean choice rate of sequence A when it has a longer maximum run length than B by >1, controlling for similar proportion and alternation rates.
import numpy as np


def test_statistic(df):
    mask = (
        (np.abs(df["p_a"] - df["p_b"]) < 0.2)
        & (np.abs(df["p_alts_a"] - df["p_alts_b"]) < 0.2)
        & (df["max_run_a"] > df["max_run_b"] + 1)
    )
    return float(df.loc[mask, "chose_left"].mean())
